"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[22250],{25414:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a builder. `getUserId` resolves the UserId used to key a player\'s envelope slice; it is\\ninjected (rather than reading `player.UserId` directly) so a headless test can stand in a fake player.","params":[{"name":"getUserId","desc":"","lua_type":"((Player) -> number)?"}],"returns":[{"desc":"","lua_type":"TeleportDataBuilder"}],"function_type":"static","source":{"line":58,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}},{"name":"RegisterTeleportDataProvider","desc":"Registers a provider that contributes teleport data on every [TeleportDataBuilder.BuildTeleportData]\\ncall. Returns a function that unregisters the provider (also give it to a [Maid]).","params":[{"name":"self","desc":"","lua_type":"TeleportDataBuilder"},{"name":"provider","desc":"","lua_type":"TeleportDataProvider"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":77,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}},{"name":"RegisterPerPlayerTeleportDataProvider","desc":"Registers a per-player provider that contributes each player\'s own slice on every\\n[TeleportDataBuilder.BuildTeleportData] call. Returns a function that unregisters it (also give it to\\na [Maid]).","params":[{"name":"self","desc":"","lua_type":"TeleportDataBuilder"},{"name":"provider","desc":"","lua_type":"PerPlayerTeleportDataProvider"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":101,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}},{"name":"BuildTeleportData","desc":"Builds the teleport data for a teleport of the given players as a per-player envelope (see\\n[TeleportDataEnvelopeUtils]): shared-provider contributions plus `baseData` form the shared slice, and\\neach per-player provider\'s contribution forms that player\'s slice.\\n\\nPrecedence, least to most specific: shared providers, then `baseData` (the caller\'s shared override),\\nthen per-player providers.\\n\\nErrors if the result exceeds the teleport-data size cap, and warns as it approaches it, so an\\noversized payload fails loudly here instead of being silently dropped by the teleport.","params":[{"name":"self","desc":"","lua_type":"TeleportDataBuilder"},{"name":"players","desc":"","lua_type":"{ Player }"},{"name":"baseData","desc":"shared caller keys, overriding shared providers","lua_type":"{ [string]: any }?"}],"returns":[{"desc":"","lua_type":"{ [string]: any }"}],"function_type":"static","source":{"line":132,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}}],"properties":[],"types":[{"name":"TeleportDataProvider","desc":"Contributes teleport data shared by *every* player in a teleport. Returns nil to contribute nothing.","lua_type":"({ Player }) -> ({ [string]: any }?)","source":{"line":26,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}},{"name":"PerPlayerTeleportDataProvider","desc":"Contributes teleport data for a *single* player in a teleport (called once per player, with the full\\nplayer list for context). Returns nil to contribute nothing. This is how per-player data survives a\\ngroup teleport, where every player would otherwise share one flat table.","lua_type":"(Player, { Player }) -> ({ [string]: any }?)","source":{"line":36,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}}],"name":"TeleportDataBuilder","desc":"Realm-agnostic assembly of the teleport-data envelope: the provider registry plus\\n[TeleportDataBuilder.BuildTeleportData]. Both [TeleportDataService] (server) and\\n[TeleportDataServiceClient] (client) own one of these and delegate their build surface to it, so a\\nteleport authored on either realm goes through the *same* providers and produces the *same* envelope\\nshape. That symmetry is the point: a client-initiated teleport can no longer forget shared data or\\nhand-roll a divergent table.\\n\\nPure -- it performs no teleport and touches no [Player] state beyond the injected UserId resolver --\\nso it is unit tested without any real player.","source":{"line":15,"path":"src/teleportserviceutils/src/Shared/TeleportDataBuilder.lua"}}')}}]);